#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        long long **dp = (long long **)malloc(N * sizeof(long long *));
        for (int i = 0; i < N; i++) {
            dp[i] = (long long *)malloc(N * sizeof(long long));
        }
        for (int i = 0; i < N; i++) {
            dp[0][i] = 1;
        }
        for (int i = 1; i < N; i++) {
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < N; k++) {
                    if (j + k + 1 <= M) {
                        dp[i][j] = (dp[i][j] + dp[i-1][k]) % MOD;
                    }
                }
            }
        }
        long long ans = 0;
        for (int i = 0; i < N; i++) {
            ans = (ans + dp[N-1][i]) % MOD;
        }
        printf("%lld\n", ans);
        for (int i = 0; i < N; i++) {
            free(dp[i]);
        }
        free(dp);
    }
    return 0;
}

